body:
The stats widget does not work like it should when you have multiple indices. 
It only displays the default result even when you write something else in the template function. 

This does not work: 

```
    ls.addWidget(
      instantsearch.widgets.stats({
        container: '.group__ls .stats',
        templates: {
          body: function(data) {
            return 'Showing ' + data.nbHits + ' results'
          }
        }
      })
    );
```

Full code:

```
import instantsearch from 'instantsearch.js/dist/instantsearch.production.min.js'
import algoliasearch from 'algoliasearch'

const globalSearch = {
  init: app => {

    let pages = instantsearch({
      indexName: 'pages',
      searchClient: algoliasearch('*******', '*************************'),
      searchFunction: function(helper) {
        let query = pages.helper.state.query;
        ls.helper.setQuery(query);
        ls.helper.search();
        dl.helper.setQuery(query);
        dl.helper.search();
        helper.search();
      },
      searchParameters: {
        hitsPerPage: 5
      }
    });

    let ls = instantsearch({
      indexName: 'legemiddelsok',
      searchClient: algoliasearch('*********', '*************************'),
      searchParameters: {
        hitsPerPage: 5
      }
    });

    let dl = instantsearch({
      indexName: 'dopinglisten',
      searchClient: algoliasearch('*********', '*************************'),
      searchParameters: {
        hitsPerPage: 5
      }
    });

    ls.addWidget(
      instantsearch.widgets.hits({
        container: '#autocompleteLs',
        templates: {
          item: function(data) {
            let substanser = "";
            return (
              '<div class="inner"><a class="t-size-s" href="'+ siteUrl + data.uri +'"><span>' + capitalizeFirstLetter(data.title) + ' </span></span><span class="o-60">(Substans: '+substanser+')</span></a></div>'
            );
          },
          empty: function(data) {
            $('.group__ls .group__description').html('Ditt søk resulterte ikke i et eksakt treff');
          }
        }
      })
    );

    dl.addWidget(
      instantsearch.widgets.hits({
        container: '#autocompleteDl',
        templates: {
          item: function(data) {
            $('.group__dl .group__description').html(dlDefaultText);
            return (
              '<div class="inner"><a class="t-size-s" href="'+ siteUrl + data.relatedUri +'"><span>' + capitalizeFirstLetter(data.title) + ' - </span></span><span class="o-60">'+data.relatedTitle+'</span></a></div>'
            );
          },
          empty: function(data) {
            $('.group__dl .group__description').html('Ditt søk resulterte ikke i et eksakt treff.');
          }
        },
      })
    );

    pages.addWidget(
      instantsearch.widgets.hits({
        container: '#autocompletePages',
        templates: {
          item: function(data) {
            $('.group__articles .group__description').empty();
            return (
              '<div class="inner"><a class="t-size-s" href="'+ siteUrl + data.uri +'"><span>' + capitalizeFirstLetter(data.title) + '</span></a></div>'
            );
          },
          empty: function(data) {
            $('.group__articles .group__description').text('Ingen treff');
          }
        },
      })
    );

    ls.addWidget(
      instantsearch.widgets.stats({
        container: '.group__ls .stats',
        templates: {
          body: function(data) {
            return 'Showing ' + data.nbHits + ' results'
          }
        }
      })
    );

    pages.addWidget(
      instantsearch.widgets.searchBox({
        container: '#aa-search-input',
        placeholder: 'Søk i legemiddel, dopingliste o.l',
      })
    );

    ls.start();
    dl.start();
    pages.start();


  }
}

export default globalSearch
```
